@trainee_router.post("/trainee")
async def flow1(body: dict = Body()):
    encrypted_flow_data_b64 = body['encrypted_flow_data']
    encrypted_aes_key_b64 = body['encrypted_aes_key']
    initial_vector_b64 = body['initial_vector']
    decrypted_data, aes_key, iv = decrypt_request(
        encrypted_flow_data_b64, encrypted_aes_key_b64, initial_vector_b64, PHONE_NUMBER_PRIVATE_KEY)
    print(decrypted_data)


    if decrypted_data["action"]=="ping":
            response={
                "data":{
                    "status":"active"
                }
            }

    elif decrypted_data["action"]=="INIT":
            response={
                "screen":"otp_screen",
                "data":{
                       "otp_verified":False
                }
            }
    elif decrypted_data["data"]["trigger"] == "show_otp":
        mobile = decrypted_data["data"].get("mobile","")
        if mobile =="":
            response = {
                    "screen":"otp_screen",
                    "data":{
                        "error_message":"Please Enter the Valid Mobile Number"
                    }
            }
        else:
            response = {
                    "screen":"otp_screen",
                    "data":{
                        "otp_verified":True
                    }
            }
    elif decrypted_data["data"]["trigger"] == "verify_otp":
          if decrypted_data["data"]["otp"] == "":
                response = {
                      "screen":"otp_screen",
                      "data":{
                            "error_message":"Enter the Valid Otp" 
                      }
                }
          elif decrypted_data["data"]["otp"] == "123456":
                response = {
                      "screen":"Welcome_screen",
                      "data":{
                            "navigation_list": Navigation
                      }
                }
          else:
                response = {
                      "screen":"otp_screen",
                      "data":{
                            "error_message":"Enter the Valid Otp" 
                      }
                }    
    elif decrypted_data["data"]["trigger"]=="upload_doc":
           response={
                  "screen":"upload_screen",
                  "data":{
                        "document_upload":"pay_slip_month1",
                        "document_visible":True,
                        "footer_enabled":False
                    }
           }
    elif decrypted_data["data"]["trigger"]=="document_uploaded":
        if "Bank_statement" in decrypted_data["data"]:
                response={
                        "screen":"upload_screen",
                        "data":{
                            "document_visible":False,
                            "footer_enabled":True
                        }
                }
        elif "pay_slip_month3"in decrypted_data["data"]:
               response = {
                      "screen":"upload_screen",
                      "data":{
                            "document_upload":"Bank_statement",
                            "document_visible":True,
                            "footer_enabled":False
                      }
               }        
        elif "pay_slip_month2"in decrypted_data["data"]:
               response = {
                      "screen":"upload_screen",
                      "data":{
                            "document_upload":"pay_slip_month3",
                            "document_visible":True,
                            "footer_enabled":False
                      }
               }        
        elif "pay_slip_month1"in decrypted_data["data"]:
               response = {
                      "screen":"upload_screen",
                      "data":{
                            "document_upload":"pay_slip_month2",
                            "document_visible":True,
                            "footer_enabled":False
                      }
               }
    elif decrypted_data["data"]["trigger"]=="show_company":
        if decrypted_data["data"]["source"] =="company":
            response ={
                    "screen":"company_screen",
                    "data":{}
            }
        else:
            response={
                    "screen":"training_screen",
                    "data":{}
              }                  
    
    encrypted_response = encrypt_response(response, aes_key, iv)
    return PlainTextResponse(content=encrypted_response, media_type='text/plain')


